css:
.loader {
  display: inline-block;
  width: 41px;
  height: 41px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color), var(--loader-secondary-color));
  animation: squareFlip 0.85s cubic-bezier(.55,.08,.38,.97) infinite;
}
@keyframes squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }
